import React, { useState, useEffect } from 'react'
import Taskcard from './Taskcard'
import axios from 'axios'

const Tasks = () => {
  const [taskName, settaskName] = useState('')
  const [tasks, setTasks] = useState([])
  const [updateActive,setUpdateActive]=useState({title:'',isUpdate:false});

  function handleDeleteTask(id) {
    setTasks(prev => {
      const deleteTasks = prev.filter(task => task.id !== id); 
      return deleteTasks;
    });
  }

  async function handleEditTask(id){
    const edit=tasks.find(t=>t._id===id);
    settaskName(edit.title);
    setUpdateActive({title:taskName,isUpdate:true});
    await axios.put(`/api/tasks/updatetask/${id}`,{
      title:taskName
    })
    setTasks(prev=>{
      const editTask=prev.map(t=>t.id===id ? {...t,title:taskName} : t);
      return editTask;
    })
  }

  async function handleUpdate(){

  }

  async function handleAdd() {
    if (!taskName.trim()) return;

    const newtask = {
      title: taskName
    }
    const res = await axios.post('/api/tasks/addtask', newtask, {
      headers: {
        "Authorization": "Bearer eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpZCI6IjY4N2U3Y2QxNjdlYzBhMjRkYzg5YmM4MCIsImVtYWlsIjoiYWRtaW5AZ21haWwuY29tIiwiaWF0IjoxNzUzNjE5OTEwfQ.qOx6RBTekg4Tw4JlcD5RBVw5ANrk9RO3RXcO3bQMmoE"
      }
    })
    console.log(res.data)
    setTasks(prev => {
      const updatedTasks = [...prev, newtask];
      return updatedTasks;
    });

    settaskName('');
  }


  useEffect(() => {
    const storedTasks = async () => {
      const getTask = await axios.get('api/tasks/getalltasks/687e7cd167ec0a24dc89bc80', {
        headers: {
          "Authorization": "Bearer eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpZCI6IjY4N2U3Y2QxNjdlYzBhMjRkYzg5YmM4MCIsImVtYWlsIjoiYWRtaW5AZ21haWwuY29tIiwiaWF0IjoxNzUzNjE5OTEwfQ.qOx6RBTekg4Tw4JlcD5RBVw5ANrk9RO3RXcO3bQMmoE"
        }
      })
      setTasks(getTask.data);
    }
    storedTasks();
  }, [tasks]);

  return (
    <div className='task-page'>
      <h1 className="tasks-heading">Tasks</h1>

      <div className='task-header'>
        <div>
          <input className='task-name' placeholder='Enter Task title...' value={taskName} onChange={(e) => settaskName(e.target.value)} />
        </div>
        <div>
          {!updateActive.isUpdate ? <button className='task-add' onClick={handleAdd}>Add</button> : <button className='task-add' onClick={handleUpdate}>Update</button>}
        </div>
      </div>

      <div className='tasks-list'>
        {tasks.map((task) => (
          <Taskcard task={task} key={task._id} handleDeleteTask={handleDeleteTask} handleEditTask={handleEditTask} />
        ))}
      </div>
      <Stylesheet />
    </div>
  )
}
const Stylesheet = () => {
  return <style>{`
        .tasks-heading {
          font-size: 2.5rem;
          text-align: center;
          margin-bottom: 1.5rem;
        }

        .task-page {
          padding: 1rem;
          font-family: 'Cedarville Cursive', cursive;
          max-width: 1200px;
          margin: auto;
        }

        .task-header {
          display: flex;
          flex-direction: row;
          align-items: center;
          justify-content: center;
          gap: 1rem;
          flex-wrap: wrap;
          margin-bottom: 2rem;
        }

        .task-name {
          background-color: var(--secondary-color);
          border: none;
          padding: 10px 15px;
          min-width: 250px;
          border-radius: 5px;
          font-size: 1.2rem;
          font-family: 'Cedarville Cursive', cursive;
          color: var(--text);
          flex: 1 1 250px;
        }

        .task-add {
          background-color: var(--button-color);
          border: none;
          padding: 10px 15px;
          min-width: 100px;
          border-radius: 5px;
          font-size: 1.2rem;
          color: var(--bg-parchment);
          font-family: 'Cedarville Cursive', cursive;
          flex-shrink: 0;
        }

        .task-name::placeholder {
          color: var(--text);
          opacity: 1;
        }

        .tasks-list {
          display: flex;
          flex-wrap: wrap;
          justify-content: center;
          align-items: flex-start; /* key change: let cards grow independently */
          gap: 1rem;
          padding: 0 1rem;
        }

        @media (max-width: 768px) {
          .task-header {
            flex-direction: column;
            align-items: stretch;
            gap: 0.8rem;
          }

          .task-name,
          .task-add {
            width: 90%;
            font-size: 1rem;
          }

          .tasks-heading {
            font-size: 2rem;
          }
        }

        @media (max-width: 480px) {
          .task-page {
            padding: 0.5rem;
          }

          .tasks-heading {
            font-size: 1.5rem;
          }

          .task-name,
          .task-add {
            font-size: 0.95rem;
          }
        }
      `}</style>
}
export default Tasks
